1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const LOYALTY_RATE = 0.2;
8	const FOLLOW_UP_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number };
22	type Step = { op: "quote"; items: Item[] };
23	type Customer = { yearsWithMHPCO: number };
24	type Scenario = { customer: Customer; steps: Step[] };
25	type QuoteResult = { premium: number };
26	type ScenarioOutput = { results: QuoteResult[] };
27	
28	const groupCountsByType = (items: Item[]): Map<string, number> => {
29	  const counts = new Map<string, number>();
30	  for (const { type } of items) {
31	    counts.set(type, (counts.get(type) ?? 0) + 1);
32	  }
33	  return counts;
34	};
35	
36	const basePremiumForGroup = (type: string, count: number): number => {
37	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
38	  return count * BASE_PREMIUM[type];
39	};
40	
41	const basePremiumFor = (items: Item[]): number =>
42	  Array.from(groupCountsByType(items)).reduce(
43	    (total, [type, count]) => total + basePremiumForGroup(type, count),
44	    0,
45	  );
46	
47	const curseSurchargeFor = (item: Item): number =>
48	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
49	
50	const highEnchantmentSurchargeFor = (item: Item): number =>
51	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
52	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
53	    : 0;
54	
55	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
56	  curseSurchargeFor,
57	  highEnchantmentSurchargeFor,
58	];
59	
60	const surchargesForItem = (item: Item): number =>
61	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
62	
63	const itemSurchargesFor = (items: Item[]): number =>
64	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
65	
66	const firstInsuranceSurchargeFor = (basePremium: number): number =>
67	  basePremium * FIRST_INSURANCE_RATE;
68	
69	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
70	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
71	    ? basePremium * LOYALTY_RATE
72	    : 0;
73	
74	const followUpDiscountFor = (basePremium: number, quoteIndex: number): number =>
75	  quoteIndex > 0 ? basePremium * FOLLOW_UP_RATE : 0;
76	
77	const premiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
78	  const basePremium = basePremiumFor(items);
79	  return Math.ceil(
80	    basePremium +
81	      itemSurchargesFor(items) +
82	      firstInsuranceSurchargeFor(basePremium) -
83	      loyaltyDiscountFor(basePremium, customer) -
84	      followUpDiscountFor(basePremium, quoteIndex) +
85	      PROCESSING_FEE,
86	  );
87	};
88	
89	const quoteStep = (
90	  { items }: Step,
91	  customer: Customer,
92	  quoteIndex: number,
93	): QuoteResult => ({
94	  premium: premiumFor(items, customer, quoteIndex),
95	});
96	
97	export const runScenario = (input: Scenario): ScenarioOutput => ({
98	  results: input.steps.map((step, i) => quoteStep(step, input.customer, i)),
99	});
